parameters.functionCode:
// Format ticket payload
const alert = $input.first().json.alert_data;
const aiResponse = $json.candidates?.[0]?.content?.parts?.[0]?.text || '';

const ticket = {
  title: `Security Alert: ${alert.rule_description}`,
  group: "SOC-Alerts",
  state: "new",
  priority: alert.rule_level >= 10 ? "4" : "3",
  article: {
    body: `Alert Analysis:\n\n${aiResponse}\n\n--- Technical Details ---\nRule ID: ${alert.rule_id}\nLevel: ${alert.rule_level}\nAgent: ${alert.agent_name}\nMITRE: ${alert.mitre_id} - ${alert.mitre_tactic}\n\nFull Log:\n${alert.full_log}`,
    type: "note",
    sender: "System"
  },
  custom_fields: {
    soc_alert_level: alert.rule_level,
    soc_agent_id: alert.agent_id,
    soc_rule_id: alert.rule_id,
    soc_mitre_id: alert.mitre_id,
    soc_mitre_tactic: alert.mitre_tactic,
    soc_action: "pending",
    soc_confidence: 0
  }
};

return ticket;

